def chromatic_number(arr: list[int]) -> int:
    n = arr[0]
    m = arr[1]
    if n == 0:
        return 0
    if m == 0:
        return 1

    adj = [[] for _ in range(n)]
    for i in range(m):
        u = arr[2 + 2 * i]
        v = arr[2 + 2 * i + 1]
        adj[u].append(v)
        adj[v].append(u)

    def can_color(k):
        colors = [0] * n

        def is_safe(v, c):
            for u in adj[v]:
                if colors[u] == c:
                    return False
            return True

        def solve(v):
            if v == n:
                return True
            for c in range(1, k + 1):
                if is_safe(v, c):
                    colors[v] = c
                    if solve(v + 1):
                        return True
                    colors[v] = 0
            return False

        return solve(0)

    for k in range(1, n + 1):
        if can_color(k):
            return k

    return n

pub fn chromatic_number(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    if n == 0 { return 0; }
    if m == 0 { return 1; }

    let mut adj = vec![vec![]; n];
    for i in 0..m {
        let u = arr[2 + 2 * i] as usize;
        let v = arr[2 + 2 * i + 1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    fn is_safe(adj: &Vec<Vec<usize>>, colors: &Vec<i32>, v: usize, c: i32) -> bool {
        for &u in &adj[v] {
            if colors[u] == c { return false; }
        }
        true
    }

    fn solve(adj: &Vec<Vec<usize>>, colors: &mut Vec<i32>, v: usize, n: usize, k: i32) -> bool {
        if v == n { return true; }
        for c in 1..=k {
            if is_safe(adj, colors, v, c) {
                colors[v] = c;
                if solve(adj, colors, v + 1, n, k) { return true; }
                colors[v] = 0;
            }
        }
        false
    }

    for k in 1..=(n as i32) {
        let mut colors = vec![0i32; n];
        if solve(&adj, &mut colors, 0, n, k) { return k; }
    }
    n as i32
}

object ChromaticNumber {

  def chromaticNumber(arr: Array[Int]): Int = {
    val n = arr(0)
    val m = arr(1)
    if (n == 0) return 0
    if (m == 0) return 1

    val adj = Array.fill(n)(scala.collection.mutable.ListBuffer[Int]())
    for (i <- 0 until m) {
      val u = arr(2 + 2 * i)
      val v = arr(2 + 2 * i + 1)
      adj(u) += v
      adj(v) += u
    }

    def isSafe(colors: Array[Int], v: Int, c: Int): Boolean = {
      for (u <- adj(v)) {
        if (colors(u) == c) return false
      }
      true
    }

    def solve(colors: Array[Int], v: Int, k: Int): Boolean = {
      if (v == n) return true
      for (c <- 1 to k) {
        if (isSafe(colors, v, c)) {
          colors(v) = c
          if (solve(colors, v + 1, k)) return true
          colors(v) = 0
        }
      }
      false
    }

    for (k <- 1 to n) {
      val colors = Array.fill(n)(0)
      if (solve(colors, 0, k)) return k
    }
    n
  }
}

func chromaticNumber(_ arr: [Int]) -> Int {
    let n = arr[0]
    let m = arr[1]
    if n == 0 { return 0 }
    if m == 0 { return 1 }

    var adj = [[Int]](repeating: [], count: n)
    for i in 0..<m {
        let u = arr[2 + 2 * i]
        let v = arr[2 + 2 * i + 1]
        adj[u].append(v)
        adj[v].append(u)
    }

    func isSafe(_ colors: [Int], _ v: Int, _ c: Int) -> Bool {
        for u in adj[v] {
            if colors[u] == c { return false }
        }
        return true
    }

    func solve(_ colors: inout [Int], _ v: Int, _ k: Int) -> Bool {
        if v == n { return true }
        for c in 1...k {
            if isSafe(colors, v, c) {
                colors[v] = c
                if solve(&colors, v + 1, k) { return true }
                colors[v] = 0
            }
        }
        return false
    }

    for k in 1...n {
        var colors = [Int](repeating: 0, count: n)
        if solve(&colors, 0, k) { return k }
    }
    return n
}

export function chromaticNumber(arr: number[]): number {
    const n = arr[0];
    const m = arr[1];
    if (n === 0) return 0;
    if (m === 0) return 1;

    const adj: number[][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const u = arr[2 + 2 * i];
        const v = arr[2 + 2 * i + 1];
        adj[u].push(v);
        adj[v].push(u);
    }

    function isSafe(colors: number[], v: number, c: number): boolean {
        for (const u of adj[v]) {
            if (colors[u] === c) return false;
        }
        return true;
    }

    function solve(colors: number[], v: number, k: number): boolean {
        if (v === n) return true;
        for (let c = 1; c <= k; c++) {
            if (isSafe(colors, v, c)) {
                colors[v] = c;
                if (solve(colors, v + 1, k)) return true;
                colors[v] = 0;
            }
        }
        return false;
    }

    for (let k = 1; k <= n; k++) {
        const colors = new Array(n).fill(0);
        if (solve(colors, 0, k)) return k;
    }
    return n;
}
